import{_ as o,o as l,c as s,ag as i}from"./chunks/framework.DGzMGr_a.js";const g=JSON.parse('{"title":"Vite 的原理与它比 Webpack 快在哪","description":"","frontmatter":{"title":"Vite 的原理与它比 Webpack 快在哪","difficulty":"medium","tags":["Vite","ESM","esbuild","Rollup"],"estimate":15},"headers":[],"relativePath":"domains/arch/qa/qa-05-vite-principle.md","filePath":"domains/arch/qa/qa-05-vite-principle.md","lastUpdated":1783504823000}'),t={name:"domains/arch/qa/qa-05-vite-principle.md"};function n(a,e,r,p,d,c){return l(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="问答-05-进阶-vite-的原理与它比-webpack-快在哪" tabindex="-1">问答 05（进阶）：Vite 的原理与它比 Webpack 快在哪 <a class="header-anchor" href="#问答-05-进阶-vite-的原理与它比-webpack-快在哪" aria-label="Permalink to &quot;问答 05（进阶）：Vite 的原理与它比 Webpack 快在哪&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>请说明 Vite 的整体架构、开发模式和生产模式各自靠什么、以及为什么冷启动比 Webpack 快得多。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>开发模式：dev server + 原生 ESM</strong></p><ul><li>开发时启动一个基于 Koa/connect 的 HTTP server，浏览器请求 <code>index.html</code> 后逐个 <code>import</code> 模块。</li><li>Vite <strong>不打包</strong>开发产物，而是把每个 import 请求当作一次 HTTP 请求，服务器按需响应对应模块。</li><li>服务器端做的转换： <ul><li><strong>依赖预构建</strong>：首次启动扫描项目，把 <code>node_modules</code> 里的 CJS 依赖用 <strong>esbuild</strong> 打成 ESM，放到 <code>node_modules/.vite</code>；同时把每个包合并成单个文件，减少 HTTP 请求。</li><li><strong>源码转换</strong>：<code>.ts</code> / <code>.tsx</code> / <code>.vue</code> / <code>.jsx</code> 由 esbuild / Vue SFC compiler / SWC 现场编译成 ESM。</li><li><strong>路径改写</strong>：<code>import x from &#39;vue&#39;</code> 改成 <code>import x from &#39;/node_modules/.vite/deps/vue.js&#39;</code>（bare import → 绝对路径）。</li><li><strong>HMR</strong>：注入客户端 runtime，通过 WebSocket 推送变更；每个模块自带 <code>import.meta.hot</code> API。</li></ul></li></ul><p><strong>生产模式：Rollup 打包</strong></p><ul><li>生产构建走 <strong>Rollup</strong>（Vite 5 起可选 Rolldown）： <ul><li>Rollup 生态成熟、tree-shaking 优秀、产物干净。</li><li>Vite 提供一层薄的 config 层，把 Vite 插件（<code>vite plugin</code>）适配到 Rollup 插件接口。</li><li>内置合理的 splitChunks 策略、CSS 处理、asset 处理、legacy build 支持。</li></ul></li></ul><p><strong>为什么冷启动快</strong></p><ol><li><strong>不打包</strong>：Webpack 冷启动要构建整个模块图（模块数量指数增长），Vite 只要把入口 HTML 返回，剩下的浏览器按需拉。</li><li><strong>依赖预构建用 esbuild</strong>：Go 写的 esbuild 处理 node_modules 打包比 Node.js 写的 Babel/Webpack 快数十倍。</li><li><strong>源码转换按需</strong>：只在浏览器真正 import 到某模块时才转换，未使用的路由/组件不会被处理。</li><li><strong>浏览器缓存友好</strong>：预构建产物打 hash + 强缓存，二次启动几乎瞬时。</li><li><strong>HMR 更轻</strong>：只需失效变化的模块及其 <code>import.meta.hot.accept</code> 边界，无需跑完整 compilation。</li></ol><p><strong>代价与权衡</strong></p><ul><li>首次访问某个未预构建的依赖时会触发<strong>动态预构建</strong>，页面出现短暂 <code>504 (Outdated Optimize Dep)</code> 或 reload。</li><li>页面初次加载会发出<strong>很多个 HTTP 请求</strong>（一个模块一个）。HTTP/2 下可承受，但网络慢时开发体验略差。</li><li>生产依然是打包产物，和 Webpack 差别没有开发时那么夸张。</li><li>IE / 不支持 ESM 的环境需要 <code>@vitejs/plugin-legacy</code> 兜底。</li></ul><p><strong>架构一览</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[浏览器] ---ESM import---&gt; [Vite Dev Server]</span></span>
<span class="line"><span>                                |</span></span>
<span class="line"><span>                +---------------+---------------+</span></span>
<span class="line"><span>                |                               |</span></span>
<span class="line"><span>         依赖预构建 (esbuild)           源码转换 (esbuild/SWC/SFC)</span></span>
<span class="line"><span>                |                               |</span></span>
<span class="line"><span>       node_modules/.vite/deps         src/App.tsx -&gt; ESM</span></span>
<span class="line"><span>                                                |</span></span>
<span class="line"><span>                                          [浏览器执行]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="追问-1-为什么要-依赖预构建-直接用-node-modules-里的-esm-不行吗" tabindex="-1">追问 1：为什么要&quot;依赖预构建&quot;？直接用 node_modules 里的 ESM 不行吗？ <a class="header-anchor" href="#追问-1-为什么要-依赖预构建-直接用-node-modules-里的-esm-不行吗" aria-label="Permalink to &quot;追问 1：为什么要&quot;依赖预构建&quot;？直接用 node_modules 里的 ESM 不行吗？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>现实是 npm 生态<strong>大量包仍是 CJS</strong>，浏览器不认 <code>require</code>，必须转换。</li><li>就算是 ESM 包，也常常拆成几十上百个小文件（<code>lodash-es</code> 的每个函数一个文件），如果不合并，浏览器要发几百个请求，慢到不能用。</li><li>预构建做两件事：<strong>CJS → ESM 转换</strong> + <strong>合并小文件</strong>（比如把 <code>lodash-es</code> 合并成单 chunk）。</li><li>触发时机：首次启动、<code>vite.config.ts</code> 或 <code>package.json</code> deps 变化、命中新的 bare import。缓存在 <code>node_modules/.vite/</code>，命中缓存就跳过。</li></ul><h2 id="追问-2-vite-生产为什么用-rollup-而不是-esbuild" tabindex="-1">追问 2：Vite 生产为什么用 Rollup 而不是 esbuild？ <a class="header-anchor" href="#追问-2-vite-生产为什么用-rollup-而不是-esbuild" aria-label="Permalink to &quot;追问 2：Vite 生产为什么用 Rollup 而不是 esbuild？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>esbuild 快</strong>，但功能相对精简： <ul><li>Tree-shaking 不如 Rollup 精细（对复杂副作用识别较弱）；</li><li>代码分割策略、chunk 命名、动态 import chunk 化的能力较弱；</li><li>插件生态少，Vue SFC、CSS module、legacy build 等高级场景不成熟。</li></ul></li><li>Rollup 生态成熟，产物质量高，Vite 复用大量 Rollup 插件（<code>@rollup/plugin-node-resolve</code>、<code>@rollup/plugin-commonjs</code>）。</li><li>Vite 团队现在推 <strong>Rolldown</strong>（Rust 写的 Rollup 兼容打包器），目标是&quot;更快 + Rollup 生态兼容&quot;，未来会替代 Rollup 做生产构建。</li></ul><h2 id="追问-3-vite-的-hmr-相比-webpack-有什么优势" tabindex="-1">追问 3：Vite 的 HMR 相比 Webpack 有什么优势？ <a class="header-anchor" href="#追问-3-vite-的-hmr-相比-webpack-有什么优势" aria-label="Permalink to &quot;追问 3：Vite 的 HMR 相比 Webpack 有什么优势？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>模块粒度更精细</strong>：Vite 每个模块本来就是独立 URL，改动谁就重新发起该模块的请求，不需要维护整个 chunk 的更新映射。</li><li><strong>API 更现代</strong>：<code>import.meta.hot.accept</code>、<code>hot.dispose</code>、<code>hot.on(&#39;vite:beforeUpdate&#39;)</code> 等，配合框架层（<code>@vitejs/plugin-react</code> 集成 React Refresh，Vue SFC 天然支持）几乎零配置就能&quot;改代码即热更&quot;。</li><li><strong>速度</strong>：Webpack 需要重新跑一次 compilation（哪怕是增量），依赖多时几百 ms 起步；Vite 只需转换单个文件，通常 10~50ms 内完成。</li><li><strong>反向优势</strong>：Webpack 打完的 HMR 更接近生产产物，某些和 chunk 有关的 bug 更早暴露；Vite 开发和生产环境差异更大，个别问题（依赖顺序、副作用）只有生产才复现。所以严肃项目<strong>开发用 Vite，也要定期跑生产构建</strong>。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/arch/RESOURCES">工程架构 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://vite.dev/guide/" target="_blank" rel="noreferrer">Vite Guide</a>：开发服务器、原生 ESM 加载与生产构建的整体架构。</li><li><a href="https://vite.dev/guide/dep-pre-bundling.html" target="_blank" rel="noreferrer">Vite: Dependency Pre-Bundling</a>：esbuild 预构建 CJS 依赖、合并小文件的动机与缓存机制。</li><li><a href="https://vite.dev/guide/features.html" target="_blank" rel="noreferrer">Vite: Features</a>：HMR、<code>import.meta.glob</code> 与插件钩子等核心能力一览。</li></ul>`,26)])])}const m=o(t,[["render",n]]);export{g as __pageData,m as default};
